import { spawn } from "node:child_process";
function tailText(text, size) {
    return text.length > size ? text.slice(text.length - size) : text;
}
export async function runJsonlCli(command, args, cwd, stdinText, callbacks) {
    return new Promise((resolve, reject) => {
        const child = spawn(command, args, {
            cwd,
            stdio: ["pipe", "pipe", "pipe"],
        });
        let stderr = "";
        let stdoutBuffer = "";
        let callbackQueue = Promise.resolve();
        let failed = false;
        const queue = (fn) => {
            callbackQueue = callbackQueue.then(async () => {
                if (failed) {
                    return;
                }
                await fn();
            });
            callbackQueue.catch((error) => {
                failed = true;
                child.kill("SIGTERM");
                reject(error);
            });
        };
        child.stdout.on("data", (chunk) => {
            stdoutBuffer += chunk.toString("utf8");
            let newlineIndex = stdoutBuffer.indexOf("\n");
            while (newlineIndex >= 0) {
                const line = stdoutBuffer.slice(0, newlineIndex).trim();
                stdoutBuffer = stdoutBuffer.slice(newlineIndex + 1);
                if (line) {
                    queue(() => callbacks.onLine(line));
                }
                newlineIndex = stdoutBuffer.indexOf("\n");
            }
        });
        child.stderr.on("data", (chunk) => {
            const text = chunk.toString("utf8");
            stderr = tailText(stderr + text, 12_000);
            if (callbacks.onStderr) {
                queue(() => callbacks.onStderr?.(text));
            }
        });
        child.on("error", (error) => {
            failed = true;
            reject(error);
        });
        child.on("close", async (code, signal) => {
            if (failed) {
                return;
            }
            const remain = stdoutBuffer.trim();
            if (remain) {
                queue(() => callbacks.onLine(remain));
            }
            try {
                await callbackQueue;
                resolve({
                    code: code ?? 1,
                    signal,
                    stderrTail: stderr.trim(),
                });
            }
            catch (error) {
                reject(error);
            }
        });
        child.stdin.write(stdinText);
        child.stdin.end();
    });
}
